GUIAnimConfig = {}

local guiAnims = {}

local startElementName = ""

local guiAnim = {
    childs = {},
}

local subAnim = {}

local function parseAttribute(name,value)
    if startElementName == "guiAnim" then
        guiAnim[name] = value
    elseif startElementName == "subAnim" then
        subAnim[name] = value
    end
end

function GUIAnimConfig:init(name)
    local path = FileUtil:getMapPath() .. name
    local file = io.open(path)
    if not file then
        LogUtil.log(string.format("FileUtil.getConfigFromXml %s failed", name), LogUtil.LogLevel.Error)
        return
    end

    local myxml = file:read('*all')

    -- Specify as many/few of these as you like
    parser = SLAXML:parser{
        startElement = function(name,nsURI,nsPrefix)
            --print(name,nsURI,nsPrefix)
            startElementName = name
        end, -- When "<foo" or <x:foo is seen
        attribute    = function(name,value,nsURI,nsPrefix)
            --print(name,value,nsURI,nsPrefix)
            parseAttribute(name,value)
        end, -- attribute found on current element
        closeElement = function(name,nsURI)
            --print("closeElement " .. name,nsURI)

            if name == "guiAnim" then
                table.insert(guiAnims, guiAnim)
                guiAnim = {
                    childs = {},
                }
            elseif name == "subAnim" then
                table.insert(guiAnim.childs, subAnim)
                subAnim = {}
            end
        end, -- When "</foo>" or </x:foo> or "/>" is seen
        --text         = function(text,cdata)                end, -- text and CDATA nodes (cdata is true for cdata nodes)
        --comment      = function(content)                   end, -- comments
        --pi           = function(target,content)            end, -- processing instructions e.g. "<?yes mon?>"
    }

    -- Ignore whitespace-only text nodes and strip leading/trailing whitespace from text
    -- (does not strip leading/trailing whitespace from CDATA)
    parser:parse(myxml,{stripWhitespace=true})

    LogUtil.log("GUIAnimConfig:init " .. inspect.inspect(guiAnims))
end

function GUIAnimConfig:getGUIAnimConfig(animName)
    for _, guiAnim in pairs(guiAnims) do
        if guiAnim.animName == animName then
            return guiAnim
        end
    end
    return nil
end

return GUIAnimConfig